<?php
 namespace WPAICG; use WPAICG\Core\Providers\Google\GoogleSettingsHandler; use WP_Error; if (!defined('ABSPATH')) { exit; } if (!class_exists('\\WPAICG\\AIPKIT_AI_Settings')) { class AIPKIT_AI_Settings { public static $default_ai_params = array( 'temperature' => 1.0, 'top_p' => 1.0, 'frequency_penalty' => 0.0, 'presence_penalty' => 0.0, ); public static $default_api_keys = array( 'public_api_key' => '', ); public static function init() { $google_settings_handler_path = WPAICG_PLUGIN_DIR . 'classes/core/providers/google/bootstrap-provider-strategy.php'; if (!class_exists(GoogleSettingsHandler::class) && file_exists($google_settings_handler_path)) { require_once $google_settings_handler_path; } if (class_exists(GoogleSettingsHandler::class) && method_exists(GoogleSettingsHandler::class, 'check_and_init_safety_settings')) { GoogleSettingsHandler::check_and_init_safety_settings(); } self::check_and_init_ai_parameters(); self::check_and_init_api_keys(); } private static function check_and_init_ai_parameters() { $opts = get_option('aipkit_options', array()); if (!isset($opts['ai_parameters']) || !is_array($opts['ai_parameters'])) { $opts['ai_parameters'] = self::$default_ai_params; update_option('aipkit_options', $opts, 'no'); } else { $final_params = []; foreach (self::$default_ai_params as $key => $default_value) { $final_params[$key] = $opts['ai_parameters'][$key] ?? $default_value; } if ($final_params !== $opts['ai_parameters']) { $opts['ai_parameters'] = $final_params; update_option('aipkit_options', $opts, 'no'); } } } private static function check_and_init_api_keys() { $opts = get_option('aipkit_options', array()); if (!isset($opts['api_keys']) || !is_array($opts['api_keys'])) { $opts['api_keys'] = self::$default_api_keys; update_option('aipkit_options', $opts, 'no'); } else { $merged = array_merge(self::$default_api_keys, $opts['api_keys']); if ($merged !== $opts['api_keys']) { $opts['api_keys'] = $merged; update_option('aipkit_options', $opts, 'no'); } } } public static function get_ai_parameters(): array { $opts = get_option('aipkit_options', array()); self::check_and_init_ai_parameters(); $opts = get_option('aipkit_options', array()); return $opts['ai_parameters'] ?? self::$default_ai_params; } public static function get_api_keys(): array { $opts = get_option('aipkit_options', array()); self::check_and_init_api_keys(); $opts = get_option('aipkit_options', array()); return $opts['api_keys'] ?? self::$default_api_keys; } } AIPKIT_AI_Settings::init(); } 